from flask import Flask, send_from_directory, abort
import os

app = Flask(__name__)
UPLOADS_DIR = os.path.join(app.root_path, 'uploads')

def is_safe_path(base, path):
    return os.path.abspath(path).startswith(os.path.abspath(base))

@app.route('/uploads/<path:filename>', methods=['GET'])
def serve_file(filename):
    # Canonicalize and validate the file path
    safe_filename = os.path.normpath(filename)
    full_path = os.path.join(UPLOADS_DIR, safe_filename)

    if not is_safe_path(UPLOADS_DIR, full_path):
        abort(403)  # Forbidden

    # Check for legacy naming conventions
    legacy_filename = f"legacy_{safe_filename}"
    legacy_path = os.path.join(UPLOADS_DIR, legacy_filename)

    if os.path.exists(legacy_path):
        return send_from_directory(UPLOADS_DIR, legacy_filename)
    
    if os.path.exists(full_path):
        return send_from_directory(UPLOADS_DIR, safe_filename)

    abort(404)  # Not Found

if __name__ == '__main__':
    app.run(debug=True)